/*
 * branching
 * Targets: if / else / else-if chains. Each function's result is stored first
 * (one call per statement), then all of them are checked in one boolean.
 */

function sign(n) {
	if (n < 0)
		return "negative";
	else if (n == 0)
		return "zero";
	else
		return "positive";
}

function grade(score) {
	if (score >= 90)      return "A";
	else if (score >= 80) return "B";
	else if (score >= 70) return "C";
	else if (score >= 60) return "D";
	else                  return "F";
}

function nested(p, q) {
	if (p > 0)
		if (q > 0)
			return "both";
		else
			return "only-p";
	else
		return "neither";
}

s1 = sign(-4);
s2 = sign(0);
s3 = sign(9);
g1 = grade(95);
g2 = grade(72);
g3 = grade(40);
n1 = nested(4, 6);

ok =     (s1 == "negative")
     and (s2 == "zero")
     and (s3 == "positive")
     and (g1 == "A")
     and (g2 == "C")
     and (g3 == "F")
     and (n1 == "both");

print("branching all correct = ", ok, "\n");

/*
 * functions
 * Targets: CALL, FUNCENTER, FUNCEXIT, PUSHARG, return values, functions as
 * values and as arguments. Each result is stored first (one call per
 * statement), then verified in one boolean.
 */

function f()        { return "hello from f"; }
function dbl(x)     { return x * 2; }
function add(a, b)  { return a + b; }
function max3(a, b, c) {
	m = a;
	if (b > m) m = b;
	if (c > m) m = c;
	return m;
}
function classify(n) {
	if (n < 10) return "small";
	return "big";
}
function apply(fn, v) { return fn(v); }

square = (function(n) { return n * n; });

r1 = f();
r2 = dbl(42);
r3 = add(10, 20);
r4 = max3(4, 9, 2);
r5 = classify(3);
r6 = square(5);
r7 = apply(dbl, 5);

ok =     (r1 == "hello from f")
     and (r2 == 84)
     and (r3 == 30)
     and (r4 == 9)
     and (r5 == "small")
     and (r6 == 25)
     and (r7 == 10);

print("functions all correct = ", ok, "\n");

/*
 * loops
 * Targets: while and for loops, plus 'break' and 'continue'. Instead of printing
 * each loop's progress, every loop accumulates into a number and the totals are
 * summed.
 *
 *  55     while: sum 1..10
 * 120     for:   product 1..5
 *  15     for:   countdown 5+4+3+2+1
 *   6     break: iterations counted before breaking at 7 (1..6)
 *  25     continue: sum of odds 1..9 (skipping evens)
 *   6     nested: total stars in a 1+2+3 triangle
 * = 227
 */

// while: sum of 1..10
i = 1; whileSum = 0;
while (i <= 10) { whileSum = whileSum + i; i = i + 1; }

// for: product of 1..5
forProd = 1;
for (k = 1; k <= 5; ++k) forProd = forProd * k;

// for: countdown accumulated
countdown = 0;
for (c = 5; c > 0; --c) countdown = countdown + c;

// break: count iterations until we bail at 7
breakCount = 0;
for (b = 1; b < 100; ++b) {
	if (b == 7) break;
	breakCount = breakCount + 1;
}

// continue: sum odd numbers 1..10, skipping evens
oddSum = 0;
for (m = 1; m <= 10; ++m) {
	if (m % 2 == 0) continue;
	oddSum = oddSum + m;
}

// nested loops: count stars in a triangle of rows 1..3
stars = 0;
for (row = 1; row <= 3; ++row)
	for (col = 1; col <= row; ++col)
		stars = stars + 1;

total = whileSum + forProd + countdown + breakCount + oddSum + stars;
print("loops total = ", total, "\n");

/*
 * scope and the :: global resolver
 * Targets: global vs. local slots, the 'local' keyword, and '::name' reaching a
 * global that a same-named local would otherwise shadow. Each effect is a number
 * (function results stored first) and they are summed.
 *
 *  100     readsGlobal(): reads ::g
 *   -1     makesLocal():  returns a local, separate from the global
 *  100     g is still 100 (the local did not leak)
 *    7     shadowLocal(): returns the shadowing local
 *  100     shadowGlobal(): returns ::g despite the local shadow
 *    6     tick() three times -> 1 + 2 + 3
 * = 312
 */

g = 100;
function readsGlobal()  { return ::g; }
function makesLocal()   { local g = -1; return g; }
function shadowLocal()  { local g = 7;  return g; }
function shadowGlobal() { local g = 7;  return ::g; }

counter = 0;
function tick() { ::counter = ::counter + 1; return ::counter; }

rg = readsGlobal();
ml = makesLocal();
sl = shadowLocal();
sg = shadowGlobal();
t1 = tick();
t2 = tick();
t3 = tick();

total = rg + ml + g + sl + sg + t1 + t2 + t3;
print("scope total = ", total, "\n");

/*
 * short-circuit evaluation (feature / deduction check)
 * Targets: 'or' must stop as soon as its left operand is true. foo() returns a
 * truthy value, so bar() must NEVER be called -- its "Hello" must not appear.
 */

function foo(){
	print("Marvelous");
	return 1;
}

function bar(){
	print("Hello");
	return 1;
}


if (foo() or bar()) {
	print("World\n");
}

/*
 * strings
 * Targets: string equality (== / !=) and escape sequences handled by the lexer.
 * The equality checks fold into one boolean; a second line shows escapes
 * rendering.
 *
 */

hello = "Hello";
same  = "Hello";

ok =     (hello == same)
     and ("abc" == "abc")
     and ("abc" != "abd")
     and (not ("x" == "y"))
     and ("" != "nonempty");

print("strings all correct = ", ok, "\n");
// Escape sequences render in the output (tab and a literal quote).
print("escapes: tab[\t] quote[\"] end\n");

/*
 * tables
 * Targets: NEWTABLE, TABLESETELEM, TABLEGETELEM, dot sugar, objecttotalmembers,
 * and nil-deletion. Each fact is captured as a boolean as we go (so ordering is
 * respected), then AND-ed into one result.
 */

list = [10, 20, 30];
c1 = list[0] == 10 and list[1] == 20 and list[2] == 30;

len1 = objecttotalmembers(list);
c2 = len1 == 3;

list[3] = 40;                                  // append
len2 = objecttotalmembers(list);
c3 = list[3] == 40 and len2 == 4;

record = [ {"name" : "Ada"}, {"year" : 1815}, {"job" : "mathematician"} ];
c4 = record.name == "Ada"
     and record.year == 1815
     and record["job"] == "mathematician";     // dot and bracket syntax

box = [ {"inner" : [ {"value" : "deep"} ]} ];
c5 = box.inner.value == "deep";                // nested access

record.year = 99;                              // overwrite
c6 = record.year == 99;

before = objecttotalmembers(record);
record.job = nil;                              // nil deletes the key
after = objecttotalmembers(record);
c7 = after == before - 1;

ok = c1 and c2 and c3 and c4 and c5 and c6 and c7;
print("tables all correct = ", ok, "\n");

/*
 * bubble sort
 * Sorts an array (a table with integer keys) in place using nested loops and a
 * swap. Exercises tables, loops and a helper that mutates a table argument
 * (tables are passed by reference).
 */

function printArray(arr, n) {
	for (i = 0; i < n; ++i)
		print(" ", arr[i]);
	print("\n");
}

function bubbleSort(arr, n) {
	for (i = 0; i < n - 1; ++i) {
		for (j = 0; j < n - 1 - i; ++j) {
			if (arr[j] > arr[j + 1]) {
				tmp = arr[j];
				arr[j] = arr[j + 1];
				arr[j + 1] = tmp;
			}
		}
	}
}

function isSorted(arr, n) {
	for (i = 1; i < n; ++i)
		if (arr[i - 1] > arr[i])
			return false;
	return true;
}

data = [5, 2, 9, 1, 5, 6, 3, 8, 7, 0];
n = objecttotalmembers(data);

print("before:");
printArray(data, n);

bubbleSort(data, n);

print("after :");
printArray(data, n);

print("sorted ascending: ", isSorted(data, n), "\n");

/*
 * Dijkstra's shortest paths
 * Single-source shortest paths on a small weighted graph given as an adjacency
 * matrix (a table of tables). A large sentinel stands in for "no edge" /
 * "infinity". Exercises nested tables, loops and a classic algorithm.
 *
 * Edges (undirected): 0-1:7  0-5:9  1-2:9  1-5:14  2-3:11  3-4:6  4-5:9
 */

INF = 100000;
N = 6;

// Symmetric adjacency matrix; 0 on the diagonal, INF where there is no edge.
g = [
	[ 0,  7,  INF, INF, INF, 9   ],
	[ 7,  0,  9,   INF, INF, 14  ],
	[ INF,9,  0,   11,  INF, INF ],
	[ INF,INF,11,  0,   6,   INF ],
	[ INF,INF,INF, 6,   0,   9   ],
	[ 9,  14, INF, INF, 9,   0   ]
];

dist = [];
visited = [];
for (i = 0; i < N; ++i) {
	dist[i] = INF;
	visited[i] = false;
}
dist[0] = 0;

for (count = 0; count < N; ++count) {
	// Pick the nearest unvisited vertex.
	u = -1;
	best = INF + 1;
	for (v = 0; v < N; ++v) {
		if (not visited[v] and dist[v] < best) {
			best = dist[v];
			u = v;
		}
	}

	if (u == -1)
		break;                       // remaining vertices unreachable

	visited[u] = true;

	// Relax all edges out of u.
	for (w = 0; w < N; ++w) {
		edge = g[u][w];
		if (edge < INF and not visited[w]) {
			alt = dist[u] + edge;
			if (alt < dist[w])
				dist[w] = alt;
		}
	}
}

print("shortest distance from vertex 0:\n");
for (i = 0; i < N; ++i)
	print("  to ", i, " = ", dist[i], "\n");

/*
 * Fibonacci
 * Computes the Fibonacci sequence two ways -- iteratively and recursively --
 * and shows they agree. Exercises loops, recursion, tables and functions.
 */

// Iterative: build the first n Fibonacci numbers into a table.
function fibSeq(n) {
	seq = [];
	seq[0] = 0;
	seq[1] = 1;
	for (i = 2; i < n; ++i)
		seq[i] = seq[i - 1] + seq[i - 2];
	return seq;
}

// Recursive definition.
function fibRec(n) {
	if (n < 2)
		return n;
	return fibRec(n - 1) + fibRec(n - 2);
}

seq = fibSeq(15);
print("iterative:");
for (i = 0; i < 15; ++i)
	print(" ", seq[i]);
print("\n");

r = fibRec(20);
print("fib(20) recursive = ", r, "\n");

// Cross-check the two implementations agree for 0..15.
ok = true;
for (i = 0; i < 15; ++i) {
	ri = fibRec(i);
	if (ri != seq[i])
		ok = false;
}
print("recursion matches iteration for 0..15: ", ok, "\n");

/*
 * matrix multiplication
 * Multiplies two 3x3 matrices stored as tables of tables and prints the result,
 * then multiplies a matrix by the identity to show it is unchanged.
 * Exercises nested tables and triple-nested loops.
 */

function makeZero(n) {
	m = [];
	for (i = 0; i < n; ++i) {
		m[i] = [];
		for (j = 0; j < n; ++j)
			m[i][j] = 0;
	}
	return m;
}

function multiply(a, b, n) {
	c = makeZero(n);
	for (i = 0; i < n; ++i)
		for (j = 0; j < n; ++j) {
			s = 0;
			for (k = 0; k < n; ++k)
				s = s + a[i][k] * b[k][j];
			c[i][j] = s;
		}
	return c;
}

function printMatrix(m, n) {
	for (i = 0; i < n; ++i) {
		for (j = 0; j < n; ++j)
			print(" ", m[i][j]);
		print("\n");
	}
}

function equalMatrix(a, b, n) {
	for (i = 0; i < n; ++i)
		for (j = 0; j < n; ++j)
			if (a[i][j] != b[i][j])
				return false;
	return true;
}

N = 3;

A = [
	[ 1, 2, 3 ],
	[ 4, 5, 6 ],
	[ 7, 8, 9 ]
];

B = [
	[ 9, 8, 7 ],
	[ 6, 5, 4 ],
	[ 3, 2, 1 ]
];

I = [
	[ 1, 0, 0 ],
	[ 0, 1, 0 ],
	[ 0, 0, 1 ]
];

AB = multiply(A, B, N);
print("A x B =\n");
printMatrix(AB, N);

AI = multiply(A, I, N);
same = equalMatrix(AI, A, N);
print("A x I == A : ", same, "\n");

/*
 * N-Queens (solution counter + one printed board)
 * Counts every way to place N non-attacking queens on an NxN board via
 * backtracking, and prints the first solution found.
 */

count = 0;
firstBoard = 0;        // will hold a copy of the column array for the first hit

// col[r] = column of the queen on row r. 'placed' rows are 0..row-1.
function safe(col, row, c) {
	for (r = 0; r < row; ++r) {
		cc = col[r];
		if (cc == c)
			return false;              // same column
		d = row - r;
		if (cc == c - d or cc == c + d)
			return false;              // same diagonal
	}
	return true;
}

function snapshot(col, n) {
	copy = [];
	for (r = 0; r < n; ++r)
		copy[r] = col[r];
	return copy;
}

function solve(col, row, n) {
	if (row == n) {
		::count = ::count + 1;
		if (not ::firstBoard)              // 0 until the first solution is stored
			::firstBoard = snapshot(col, n);
		return;
	}
	for (c = 0; c < n; ++c) {
		if (safe(col, row, c)) {
			col[row] = c;
			solve(col, row + 1, n);
		}
	}
}

function countSolutions(n) {
	::count = 0;
	::firstBoard = 0;
	board = [];
	for (r = 0; r < n; ++r)
		board[r] = -1;
	solve(board, 0, n);
	return ::count;
}

s4 = countSolutions(4);
print("solutions for N=4: ", s4, "\n");

s6 = countSolutions(6);
print("solutions for N=6: ", s6, "\n");

s8 = countSolutions(8);
print("solutions for N=8: ", s8, "\n");

print("one solution for N=8:\n");
for (r = 0; r < 8; ++r) {
	for (c = 0; c < 8; ++c) {
		if (firstBoard[r] == c)
			print(" Q");
		else
			print(" .");
	}
	print("\n");
}

/*
 * Sieve of Eratosthenes
 * Finds every prime up to LIMIT. Exercises tables used as a boolean array,
 * nested loops and integer arithmetic.
 */

LIMIT = 50;

// isComposite[i] starts false (we use 0/false, never nil, as the "unset" mark).
isComposite = [];
for (i = 0; i <= LIMIT; ++i)
	isComposite[i] = false;

for (p = 2; p * p <= LIMIT; ++p) {
	if (not isComposite[p]) {
		for (m = p * p; m <= LIMIT; m = m + p)
			isComposite[m] = true;
	}
}

print("primes up to ", LIMIT, ":\n");
count = 0;
for (i = 2; i <= LIMIT; ++i) {
	if (not isComposite[i]) {
		print(" ", i);
		count = count + 1;
	}
}
print("\ncount = ", count, "\n");

/*
 * expression evaluator with a functor AST
 * Each node of an arithmetic expression tree is an object whose "()" functor
 * evaluates it, recursively calling its children's functors. Building an
 * expression is just nesting constructors; evaluating it is calling the root.
 * Exercises functors, chained/nested calls and recursion over a data structure.
 *
 * Tree built below:  ((3 + 4) * 2) - (10 / 5)  ==  14 - 2  ==  12
 * and a deeper one:   (2 * (3 + (4 * 5))) - 6   ==  2*23 - 6 ==  40
 */

function Num(v) {
	return [
		{ "v"  : v },
		{ "()" : (function(self) { return self.v; }) }
	];
}

function Add(l, r) {
	return [
		{ "l"  : l },
		{ "r"  : r },
		{ "()" : (function(self) { return self.l() + self.r(); }) }
	];
}

function Sub(l, r) {
	return [
		{ "l"  : l },
		{ "r"  : r },
		{ "()" : (function(self) { return self.l() - self.r(); }) }
	];
}

function Mul(l, r) {
	return [
		{ "l"  : l },
		{ "r"  : r },
		{ "()" : (function(self) { return self.l() * self.r(); }) }
	];
}

function Div(l, r) {
	return [
		{ "l"  : l },
		{ "r"  : r },
		{ "()" : (function(self) { return self.l() / self.r(); }) }
	];
}

// A single leaf.
leaf = Num(42);
print("leaf 42            = ", leaf(), "\n");

// 3 + 4
sum = Add(Num(3), Num(4));
print("3 + 4              = ", sum(), "\n");

// (3 + 4) * 2
prod = Mul(Add(Num(3), Num(4)), Num(2));
print("(3+4)*2            = ", prod(), "\n");

// ((3 + 4) * 2) - (10 / 5)
expr = Sub(Mul(Add(Num(3), Num(4)), Num(2)), Div(Num(10), Num(5)));
print("((3+4)*2)-(10/5)   = ", expr(), "\n");

// (2 * (3 + (4 * 5))) - 6
deep = Sub(Mul(Num(2), Add(Num(3), Mul(Num(4), Num(5)))), Num(6));
print("(2*(3+(4*5)))-6    = ", deep(), "\n");

/*
 * functors (objects you can "call")
 * A table that has a "()" member can be called like a function; the table is
 * passed as the implicit first argument.
 */

// A stateful counter object: each call bumps and returns its count.
function makeCounter() {
	return [
		{ "n"  : 0 },
		{ "()" : (function(self) {
			self.n = self.n + 1;
			return self.n;
		}) }
	];
}

counter = makeCounter();
c1 = counter();
c2 = counter();
c3 = counter();
print("counter: ", c1, " ", c2, " ", c3, "\n");

// An accumulator: call it with a number to add it to a running total.
function makeAccumulator() {
	return [
		{ "total" : 0 },
		{ "()" : (function(self, x) {
			self.total = self.total + x;
			return self.total;
		}) }
	];
}

acc = makeAccumulator();
acc(5);
acc(10);
last = acc(20);
print("accumulator total: ", last, "\n");

// A functor that returns another functor (currying-ish).
function makeAdder() {
	return [
		{ "()" : (function(self, a) {
			return [
				{ "a"  : a },
				{ "()" : (function(inner, b) { return inner.a + b; }) }
			];
		}) }
	];
}

adder = makeAdder();
add10 = adder(10);
r = add10(7);
print("adder(10)(7) = ", r, "\n");

// A calculator dispatched on an operation name through its functor.
function makeCalc() {
	return [
		{ "()" : (function(self, op, x, y) {
			if (op == "add") return x + y;
			else if (op == "mul") return x * y;
			else if (op == "sub") return x - y;
			else return nil;
		}) }
	];
}

calc = makeCalc();
a = calc("add", 6, 4);
b = calc("mul", 6, 4);
c = calc("sub", 6, 4);
print("calc add 6+4 = ", a, "\n");
print("calc mul 6*4 = ", b, "\n");
print("calc sub 6-4 = ", c, "\n");

/*
 * Conway's Game of Life
 * A glider crawling across a grid. The grid is a table of tables of 0/1 cells;
 * each generation is computed from the previous one with the standard rules.
 * Exercises nested tables, neighbour counting with bounds checks, and a fair
 * amount of looping -- and it is genuinely fun to watch evolve.
 *
 * Rules: a live cell with 2 or 3 live neighbours survives; a dead cell with
 * exactly 3 live neighbours becomes alive; everything else dies / stays dead.
 */

W = 10;
H = 8;

function makeGrid() {
	g = [];
	for (y = 0; y < H; ++y) {
		g[y] = [];
		for (x = 0; x < W; ++x)
			g[y][x] = 0;
	}
	return g;
}

function printGrid(g, gen) {
	print("generation ", gen, ":\n");
	for (y = 0; y < H; ++y) {
		for (x = 0; x < W; ++x) {
			if (g[y][x])
				print("#");
			else
				print(".");
		}
		print("\n");
	}
	print("\n");
}

function liveNeighbours(g, cx, cy) {
	n = 0;
	for (dy = -1; dy <= 1; ++dy) {
		for (dx = -1; dx <= 1; ++dx) {
			if (dx == 0 and dy == 0)
				continue;
			nx = cx + dx;
			ny = cy + dy;
			if (nx >= 0 and nx < W and ny >= 0 and ny < H)
				if (g[ny][nx])
					n = n + 1;
		}
	}
	return n;
}

function step(g) {
	next = makeGrid();
	for (y = 0; y < H; ++y) {
		for (x = 0; x < W; ++x) {
			alive = g[y][x];
			cnt = liveNeighbours(g, x, y);
			if (alive) {
				if (cnt == 2 or cnt == 3)
					next[y][x] = 1;
			} else {
				if (cnt == 3)
					next[y][x] = 1;
			}
		}
	}
	return next;
}

grid = makeGrid();
// A glider near the top-left corner.
grid[0][1] = 1;
grid[1][2] = 1;
grid[2][0] = 1;
grid[2][1] = 1;
grid[2][2] = 1;

for (gen = 0; gen < 20; ++gen) {
	printGrid(grid, gen);
	grid = step(grid);
}

/*
 * ============================================================================
 *  GROUND-TRUTH STRESS TEST  --  Alpha Virtual Machine
 * ============================================================================
 *
 * Purpose
 *   A single, self-verifying program that exercises every language feature and
 *   every library function the VM ships with, in combination. It is meant to be
 *   the reference ("ground truth") students diff their own VM output against:
 *   on a correct VM every check prints [PASS] and the final tally reads
 *   "FAILED: 0".
 *
 * How it self-checks
 *   check(label, cond) bumps a global counter and prints [PASS]/[FAIL]. Most
 *   checks reduce a computation to a boolean so the result is robust to harmless
 *   differences (e.g. table bucket ordering). Section 1 additionally prints raw
 *   values, because number/bool/nil *formatting* is itself part of the VM spec
 *   (integers use '_' as a thousands separator; decimals are %.3f, trimmed).
 *
 * Deliberately avoided (documented VM/language behavior, not bugs)
 *   - Forward references: a function may only call functions/anon-values that
 *     are already defined when its body runs. Mutual recursion is therefore
 *     expressed through globals assigned before first use (see Section 5).
 *   - Whole-table printing: the VM renders tables with ANSI colours and in
 *     hash-bucket order, which is implementation-defined; table state is checked
 *     through indexing / objecttotalmembers / objectmemberkeys instead.
 *   - Cross-type == / != (other than with bool or nil) raises a VM error, so it
 *     is never used as a passing check.
 *   - argument(i) yields the i-th actual as a NUMBER, so variadic helpers here
 *     are numeric by design.
 */

/* -------------------------------------------------------------------------- */
/*  Harness                                                                   */
/* -------------------------------------------------------------------------- */

total  = 0;
passed = 0;

function check(label, cond) {
    ::total = ::total + 1;
    if (cond) {
        ::passed = ::passed + 1;
        print("  [PASS] ", label, "\n");
    } else {
        print("  [FAIL] ", label, "\n");
    }
}

