}

function product() {
	local n = totalarguments();
	local p = 1;
	for (local i = 0; i < n; ++i)
		p = p * argument(i);
	return p;
}

function max() {
	local n = totalarguments();
	if (n == 0)
		return nil;
	local best = argument(0);
	for (local i = 1; i < n; ++i) {
		local v = argument(i);
		if (v > best)
			best = v;
	}
	return best;
}

function average() {
	local n = totalarguments();
	if (n == 0)
		return nil;
	local total = 0;
	for (local i = 0; i < n; ++i)
		total = total + argument(i);
	return total / n;
}

function countArgs() {
	return totalarguments();
}

